namespace sv_7e686d15a9c9425dbda2aa162c6a4150.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Registered as Scoped so each Blazor Server circuit (i.e. each browser tab / user)
/// gets its own independent instance.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>
    /// Raised on the calling thread after the warehouse selection changes.
    /// Subscribers must call InvokeAsync / StateHasChanged on their own synchronization context.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_7e686d15a9c9425dbda2aa162c6a4150.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and broadcasts updates
/// to all subscribed components within a single circuit.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random _random = Random.Shared;

    private int _lastKnownCount;

    public int LastKnownCount => _lastKnownCount;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }

    /// <summary>
    /// Raised after new alert data is fetched so every subscriber can re-render.
    /// </summary>
    public event Action? OnAlertDataChanged;

    /// <summary>
    /// Called by the polling component after fetching fresh data.
    /// Stores the count and notifies all subscribers.
    /// </summary>
    public void PublishUpdate(int newCount)
    {
        _lastKnownCount = newCount;
        OnAlertDataChanged?.Invoke();
    }
}

