namespace sv_7e686d15a9c9425dbda2aa162c6a4150.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and broadcasts updates
/// to all subscribed components within a single circuit.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random _random = Random.Shared;

    private int _lastKnownCount;

    public int LastKnownCount => _lastKnownCount;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }

    /// <summary>
    /// Raised after new alert data is fetched so every subscriber can re-render.
    /// </summary>
    public event Action? OnAlertDataChanged;

    /// <summary>
    /// Called by the polling component after fetching fresh data.
    /// Stores the count and notifies all subscribers.
    /// </summary>
    public void PublishUpdate(int newCount)
    {
        _lastKnownCount = newCount;
        OnAlertDataChanged?.Invoke();
    }
}

