@page "/dashboard"
@using sv_7e686d15a9c9425dbda2aa162c6a4150.Services
@rendermode InteractiveServer
@implements IDisposable
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body d-flex align-items-center gap-3">
        <span class="fs-4">⚠️</span>
        <div>
            <h5 class="card-title mb-0">Low-Stock Alerts</h5>
            <p class="card-text mb-0">
                @if (_loading)
                {
                    <span class="text-muted">Loading…</span>
                }
                else
                {
                    <span class="fw-bold fs-5 @(_alertCount > 0 ? "text-danger" : "text-success")">
                        @_alertCount
                    </span>
                    <span> items below minimum level</span>
                }
            </p>
        </div>
    </div>
    <div class="card-footer text-muted small">
        Refreshes every 10 seconds &middot; Last update: @_lastRefresh.ToString("T")
    </div>
</div>

@code {
    private int _alertCount;
    private bool _loading = true;
    private DateTime _lastRefresh;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await FetchAlerts();
        StartPolling();
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse switched — restart polling for the new site
        StopPolling();
        await InvokeAsync(async () =>
        {
            await FetchAlerts();
            StateHasChanged();
        });
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await FetchAlerts();
                    StateHasChanged();
                });
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task FetchAlerts()
    {
        _loading = true;
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _alertCount = count;
        _loading = false;
        _lastRefresh = DateTime.Now;

        // Broadcast to all subscribers (e.g. the sidebar AlertBadge)
        AlertService.PublishUpdate(count);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

